UPDATE reservation_record
user_id = #{user_id}, room_id = #{room_id}, meeting_topic = #{purpose}, reserve_date = #{reserveDate}, start_time = #{start_time}, end_time = #{end_time}, expected_num = #{expectedNum}, approval_status = #{reservation_status}, reject_reason = #{rejected_reason}, approver_id = #{approverId}, approval_time = #{approvalTime}, use_confirm = #{useConfirm}, update_time = CURRENT_TIMESTAMP
WHERE record_id = #{reservation_id}

mapper.select:
SELECT * FROM reservation_record
WHERE user_id = #{user_id}
ORDER BY reserve_date DESC, start_time DESC

SELECT * FROM reservation_record
WHERE approval_status = #{status}
ORDER BY Start_time ASC

SELECT * FROM reservation_record
WHERE room_id = #{room_id}
ORDER BY reserve_date DESC, start_time DESC

SELECT * FROM reservation_record
WHERE start_time BETWEEN #{start} AND #{end}
   OR end_time BETWEEN #{start} AND #{end}
ORDER BY start_time ASC

SELECT * FROM reservation_record
WHERE room_id = #{room_id}
  AND approval_status IN ('PENDING', 'CONFIRMED', 'IN_USE')
  AND reserve_date = #{reserve_date}
  AND (
    (start_time < #{end} AND end_time > #{start})
    )
ORDER BY start_time ASC
